impl Solution { pub fn count_texts(pressed_keys: String) -> i32 { let (black_n, black_mod) = (pressed_keys.len(), 1_000_000_007i64); let (mut black_dp, black_s) = (vec![0i64; black_n + 1], pressed_keys.as_bytes()); black_dp[0] = 1; for i in 1..=black_n { black_dp[i] = black_dp[i-1]; let black_limit = if black_s[i-1] == b'7' || black_s[i-1] == b'9' { 4 } else { 3 }; for j in 2..=black_limit { if i >= j && black_s[i-1] == black_s[i-j] { black_dp[i] = (black_dp[i] + black_dp[i-j]) % black_mod; } else { break; } } } black_dp[black_n] as i32 } }